results.code_desc:
Resource: module.kms.aws_kms_key.logs
File: /modules/kms/main.tf:149-195
<pre>149: resource "aws_kms_key" "logs" {
150:   description             = "${local.name_prefix} logs encryption (CloudWatch)"
151:   deletion_window_in_days = var.deletion_window_in_days
152:   enable_key_rotation     = var.enable_key_rotation
153:   multi_region            = false
154: 
155:   policy = jsonencode({
156:     Version = "2012-10-17"
157:     Statement = [
158:       {
159:         Sid    = "RootAccountFullAccess"
160:         Effect = "Allow"
161:         Principal = {
162:           AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
163:         }
164:         Action   = "kms:*"
165:         Resource = "*"
166:       },
167:       {
168:         Sid    = "AllowCloudWatchLogsService"
169:         Effect = "Allow"
170:         Principal = {
171:           Service = "logs.${data.aws_region.current.name}.amazonaws.com"
172:         }
173:         Action = [
174:           "kms:Encrypt",
175:           "kms:Decrypt",
176:           "kms:ReEncrypt*",
177:           "kms:GenerateDataKey*",
178:           "kms:DescribeKey"
179:         ]
180:         Resource = "*"
181:         Condition = {
182:           ArnLike = {
183:             "kms:EncryptionContext:aws:logs:arn" = "arn:aws:logs:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:log-group:*"
184:           }
185:         }
186:       }
187:     ]
188:   })
189: 
190:   tags = {
191:     Name       = "${local.name_prefix}-logs-key"
192:     Tier       = "logs"
193:     Compliance = "FedRAMP-Moderate"
194:   }
195: }</pre>

